import 'package:flutter/material.dart'; import '../main.dart'; class PlannerScreen extends StatelessWidget { @override Widget build(BuildContext context) { return WatermarkScaffold(title: 'جدول اليوم - من الفجر للـ 12 ليلا', child: ListView.builder(itemCount: 18, itemBuilder: (c,i){ final hour=4+i; return Card(margin: EdgeInsets.all(8), child: ListTile(title: Text('\${hour}:00'), subtitle: Text('اضغط لإضافة مهمة'), trailing: Icon(Icons.add), onTap: (){})); })); } }